import React, { useEffect, useState, useCallback, useMemo } from 'react';
import { Link } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { fetchFeaturedProductsRequest, fetchCategoriesRequest } from '../redux/slices/productSlice';
import { API_URL } from '../utils/api';

const heroSlides = [
  {
    id: 1,
    image: '/images/hero-phones.jpg',
    title: 'Latest Smartphones',
    subtitle: 'Get the newest phones with flexible payment options',
    category: 'Phones',
    gradient: 'from-gray-900/70 to-gray-800/70',
  },
  {
    id: 2,
    image: '/images/hero-electronics.jpg',
    title: 'Premium Electronics',
    subtitle: 'Top-quality gadgets at unbeatable prices',
    category: 'Electronics',
    gradient: 'from-gray-800/70 to-gray-900/70',
  },
  {
    id: 3,
    image: '/images/hero-furniture.jpg',
    title: 'Modern Furniture',
    subtitle: 'Transform your space with stylish furniture',
    category: 'Furniture',
    gradient: 'from-amber-900/70 to-orange-900/70',
  },
  {
    id: 4,
    image: '/images/hero-powerbank.jpg',
    title: 'Power Banks & Accessories',
    subtitle: 'Stay charged on the go with powerful accessories',
    category: 'Accessories',
    gradient: 'from-green-900/70 to-teal-900/70',
  },
];

const Home = () => {
  const dispatch = useDispatch();
  const { featuredProducts, categories } = useSelector((state) => state.products);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [isAutoPlaying, setIsAutoPlaying] = useState(true);

  const categoryPreviewProducts = useMemo(() => {
    const previewMap = new Map();

    featuredProducts.forEach((product) => {
      if (!product?.categoryId || previewMap.has(product.categoryId)) {
        return;
      }

      previewMap.set(product.categoryId, product);
    });

    return previewMap;
  }, [featuredProducts]);

  const nextSlide = useCallback(() => {
    setCurrentSlide((prev) => (prev + 1) % heroSlides.length);
  }, []);

  const prevSlide = useCallback(() => {
    setCurrentSlide((prev) => (prev - 1 + heroSlides.length) % heroSlides.length);
  }, []);

  const goToSlide = (index) => {
    setCurrentSlide(index);
    setIsAutoPlaying(false);
    setTimeout(() => setIsAutoPlaying(true), 5000);
  };

  useEffect(() => {
    dispatch(fetchFeaturedProductsRequest({ limit: 24 }));
    dispatch(fetchCategoriesRequest());
  }, [dispatch]);

  useEffect(() => {
    if (!isAutoPlaying) return;
    const interval = setInterval(nextSlide, 4000);
    return () => clearInterval(interval);
  }, [isAutoPlaying, nextSlide]);

  return (
    <div>
      {/* Hero Carousel Section */}
      <section className="relative h-[420px] sm:h-[500px] md:h-[600px] overflow-hidden">
        {/* Slides */}
        {heroSlides.map((slide, index) => (
          <div
            key={slide.id}
            className={`absolute inset-0 transition-all duration-700 ease-in-out ${
              index === currentSlide
                ? 'opacity-100 scale-100'
                : 'opacity-0 scale-105'
            }`}
          >
            {/* Background Image */}
            <div
              className="absolute inset-0 bg-cover bg-center"
              style={{ backgroundImage: `url(${slide.image})` }}
            />
            {/* Gradient Overlay */}
            <div className={`absolute inset-0 bg-gradient-to-r ${slide.gradient}`} />

            {/* Content */}
            <div className="relative h-full flex items-center">
              <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
                <div className={`max-w-xl transform transition-all duration-700 delay-200 ${
                  index === currentSlide
                    ? 'translate-y-0 opacity-100'
                    : 'translate-y-10 opacity-0'
                }`}>
                  <span className="inline-block bg-white/20 backdrop-blur-sm text-white text-xs sm:text-sm px-3 sm:px-4 py-1 rounded-full mb-4">
                    {slide.category}
                  </span>
                  <h1 className="text-3xl sm:text-4xl md:text-6xl font-bold text-white mb-4 leading-tight">
                    {slide.title}
                  </h1>
                  <p className="text-base sm:text-lg md:text-xl text-white/90 mb-6 sm:mb-8 max-w-lg">
                    {slide.subtitle}
                  </p>
                  <div className="flex flex-col sm:flex-row sm:flex-wrap gap-3 sm:gap-4">
                    <Link
                      to="/products"
                      className="bg-white text-center text-gray-900 px-6 sm:px-8 py-3 rounded-lg font-semibold hover:bg-gray-100 transition-all hover:scale-105 shadow-lg"
                    >
                      Shop Now
                    </Link>
                    <Link
                      to="/products"
                      className="border-2 border-white text-center text-white px-6 sm:px-8 py-3 rounded-lg font-semibold hover:bg-white/10 transition-all"
                    >
                      View Collection
                    </Link>
                  </div>
                </div>
              </div>
            </div>
          </div>
        ))}

        {/* Navigation Arrows */}
        <button
          onClick={() => {
            prevSlide();
            setIsAutoPlaying(false);
            setTimeout(() => setIsAutoPlaying(true), 5000);
          }}
          className="hidden sm:block absolute left-4 top-1/2 -translate-y-1/2 bg-white/20 hover:bg-white/40 backdrop-blur-sm text-white p-3 rounded-full transition-all hover:scale-110 z-10"
          aria-label="Previous slide"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
        </button>
        <button
          onClick={() => {
            nextSlide();
            setIsAutoPlaying(false);
            setTimeout(() => setIsAutoPlaying(true), 5000);
          }}
          className="hidden sm:block absolute right-4 top-1/2 -translate-y-1/2 bg-white/20 hover:bg-white/40 backdrop-blur-sm text-white p-3 rounded-full transition-all hover:scale-110 z-10"
          aria-label="Next slide"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
          </svg>
        </button>

        {/* Slide Indicators */}
        <div className="absolute bottom-4 sm:bottom-6 left-1/2 -translate-x-1/2 flex gap-2 sm:gap-3 z-10">
          {heroSlides.map((_, index) => (
            <button
              key={index}
              onClick={() => goToSlide(index)}
              className={`transition-all duration-300 ${
                index === currentSlide
                  ? 'w-7 sm:w-8 h-2.5 sm:h-3 bg-white rounded-full'
                  : 'w-2.5 sm:w-3 h-2.5 sm:h-3 bg-white/50 hover:bg-white/70 rounded-full'
              }`}
              aria-label={`Go to slide ${index + 1}`}
            />
          ))}
        </div>

        {/* Progress Bar */}
        <div className="absolute bottom-0 left-0 right-0 h-1 bg-white/20">
          <div
            className="h-full bg-white transition-all duration-300"
            style={{
              width: `${((currentSlide + 1) / heroSlides.length) * 100}%`,
            }}
          />
        </div>
      </section>

      {/* Features Banner */}
      <section className="bg-emerald-600 text-white py-4">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-wrap justify-center md:justify-between items-center gap-3 sm:gap-4 text-xs sm:text-sm">
            <div className="flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
              </svg>
              <span>Free Shipping</span>
            </div>
            <div className="flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <span>Flexible Payment Plans</span>
            </div>
            <div className="flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
              </svg>
              <span>Secure Checkout</span>
            </div>
            <div className="flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M18.364 5.636l-3.536 3.536m0 5.656l3.536 3.536M9.172 9.172L5.636 5.636m3.536 9.192l-3.536 3.536M21 12a9 9 0 11-18 0 9 9 0 0118 0zm-5 0a4 4 0 11-8 0 4 4 0 018 0z" />
              </svg>
              <span>24/7 Support</span>
            </div>
          </div>
        </div>
      </section>

      {/* Shop by Category Section */}
      {categories && categories.length > 0 && (
        <section className="py-12 md:py-16 bg-gray-50">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="text-center mb-10 md:mb-12">
              <h2 className="text-2xl md:text-3xl font-bold mb-3">Shop by Category</h2>
              <p className="text-gray-600 max-w-2xl mx-auto">
                Browse our wide range of product categories
              </p>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3 sm:gap-4 md:gap-6">
              {categories.slice(0, 8).map((category) => (
                (() => {
                  const previewProduct = categoryPreviewProducts.get(category._id);
                  const previewImage = previewProduct?.images?.[0]
                    ? `${API_URL}${previewProduct.images[0]}`
                    : category.image
                      ? `${API_URL}${category.image}`
                      : null;

                  return (
                    <Link
                      key={category._id}
                      to={`/products?category=${category._id}`}
                      className="group relative bg-white rounded-2xl overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300"
                    >
                      <div className="aspect-square overflow-hidden">
                        {previewImage ? (
                          <img
                            src={previewImage}
                            alt={previewProduct?.name || category.name}
                            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                          />
                        ) : (
                          <div className="w-full h-full bg-gradient-to-br from-emerald-100 to-emerald-200 flex items-center justify-center">
                            <svg className="w-16 h-16 text-emerald-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
                            </svg>
                          </div>
                        )}
                      </div>
                      <div className="absolute inset-0 bg-gradient-to-t from-black/75 via-black/10 to-transparent" />
                      <div className="absolute bottom-0 left-0 right-0 p-4">
                        <h3 className="text-white font-semibold text-sm sm:text-lg truncate">{category.name}</h3>
                        <p className="text-white/80 text-xs sm:text-sm truncate">
                          {previewProduct?.name || 'Shop this category'}
                        </p>
                        <p className="mt-1 text-white/80 text-xs sm:text-sm flex items-center gap-1 group-hover:text-emerald-300 transition-colors">
                          Shop Now
                          <svg className="w-4 h-4 transform group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                          </svg>
                        </p>
                      </div>
                    </Link>
                  );
                })()
              ))}
            </div>

            {categories.length > 8 && (
              <div className="text-center mt-8">
                <Link
                  to="/products"
                  className="inline-flex items-center gap-2 text-emerald-600 hover:text-emerald-700 font-semibold"
                >
                  View All Categories
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 8l4 4m0 0l-4 4m4-4H3" />
                  </svg>
                </Link>
              </div>
            )}
          </div>
        </section>
      )}

      {/* How SureBank Works Section - Emerald Green Background */}
      <section className="relative bg-emerald-700 overflow-hidden">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 md:py-24">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-10 md:gap-12 items-center">
            {/* Left Content */}
            <div className="text-white">
              <h2 className="text-3xl md:text-5xl font-bold leading-tight mb-8">
                Take control of your finances,{' '}
                <span className="text-emerald-200">you can start immediately.</span>
              </h2>

              {/* Step 1 */}
              <div className="mb-8">
                <div className="flex items-center gap-3 mb-2">
                  <div className="w-1 h-8 bg-amber-400 rounded-full"></div>
                  <h3 className="text-xl md:text-2xl font-bold">Search & Find</h3>
                </div>
                <p className="text-emerald-100 ml-4 pl-3">
                  Visit SureBank to find your desired item from our wide range of product offerings, select it and check the properties.
                </p>
              </div>

              {/* Step 2 */}
              <div className="mb-8">
                <div className="flex items-center gap-3 mb-2">
                  <div className="w-1 h-8 bg-amber-400 rounded-full"></div>
                  <h3 className="text-xl md:text-2xl font-bold">Plan & start your installment</h3>
                </div>
                <p className="text-emerald-100 ml-4 pl-3">
                  Choose your desired installment. You can choose between 4 - 48 weeks or 2 - 12 months. Then proceed to pay your first payment.
                </p>
              </div>

              {/* Step 3 */}
              <div className="mb-8">
                <div className="flex items-center gap-3 mb-2">
                  <div className="w-1 h-8 bg-amber-400 rounded-full"></div>
                  <h3 className="text-xl md:text-2xl font-bold">We will deliver at 50%</h3>
                </div>
                <p className="text-emerald-100 ml-4 pl-3">
                  Your desired item will be shipped to you before full payment at the mid-point of your installment. Start enjoying your product while you pay!
                </p>
              </div>

              <Link
                to="/products"
                className="inline-flex w-full sm:w-auto justify-center items-center gap-2 bg-amber-500 hover:bg-amber-600 text-gray-900 px-8 py-4 rounded-full font-semibold transition-all hover:scale-105 shadow-lg"
              >
                Start Shopping
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 8l4 4m0 0l-4 4m4-4H3" />
                </svg>
              </Link>
            </div>

            {/* Right Content - Phone Mockup with Products */}
            <div className="relative hidden lg:block">
              {/* Gold Background Shape */}
              <div className="absolute top-1/2 right-0 -translate-y-1/2 w-80 h-[500px] bg-amber-500 rounded-l-[60px]"></div>

              {/* Phone Frame */}
              <div className="relative z-10 mx-auto w-72">
                <div className="bg-gray-900 rounded-[3rem] p-3 shadow-2xl">
                  <div className="bg-white rounded-[2.5rem] overflow-hidden">
                    {/* Phone Header */}
                    <div className="bg-emerald-600 px-6 py-8 text-center">
                      <h4 className="text-white text-2xl font-bold leading-tight">
                        Pay<br/>Small<br/>Small
                      </h4>
                    </div>

                    {/* Products Preview */}
                    <div className="p-4">
                      <div className="flex justify-between items-center mb-3">
                        <span className="bg-emerald-600 text-white text-xs px-3 py-1 rounded-full">Latest</span>
